def get_ls_result(dir_path: str) -> str:
    try:
        result = subprocess.run(
            ['ls', '-l', dir_path],
            capture_output=True,
            text=True,
            check=False
        )
        if result.returncode != 0:
            return ''
        return result.stdout
    except:
        return ''

